from flask import Flask, request, redirect, session, jsonify
import random
import string

app = Flask(__name__)
app.secret_key = 'your_secret_key'

users = {'user1': 'password1'}
mfa_tokens = {}

def generate_mfa_token():
    return ''.join(random.choices(string.digits, k=6))

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    
    if users.get(username) == password:
        session['username'] = username
        mfa_token = generate_mfa_token()
        mfa_tokens[username] = mfa_token
        print(f'MFA token for {username}: {mfa_token}')
        return redirect('/verify-mfa')
    return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    username = session.get('username')
    token = request.form.get('token')

    if username and mfa_tokens.get(username) == token:
        session['mfa_verified'] = True
        del mfa_tokens[username]
        return jsonify({'message': 'MFA Verified'})
    return jsonify({'error': 'Invalid MFA token'}), 403

@app.route('/protected', methods=['GET'])
def protected():
    if session.get('username') and session.get('mfa_verified'):
        return jsonify({'message': 'Welcome to the protected resource!'})
    return jsonify({'error': 'Unauthorized'}), 403

if __name__ == '__main__':
    app.run(debug=True)